➡️ Ces commandes créent et vérifient la structure, rendent ton script exécutable, et remplissent inventory.csv à partir du contenu de _inbox si besoin.

bashCopier le codecd "/Users/nathalie/Dropbox/PROJETS/EURKAI/INBOX_EURKAI"
ls -1 "_inbox"
ls -l "auto_inventory.sh"
chmod +x "auto_inventory.sh"
mkdir -p "manifests"
bash "auto_inventory.sh"
ls -l "manifests/inventory.csv" || (
echo "source_path,guess_chantier,type,status,notes" > "manifests/inventory.csv"
find "_inbox" -type f | while read FILE; do
  REL="${FILE#_inbox/}"
  CHANTIER=$(echo "$REL" | grep -Eo 'C[0-9]{2}' | head -1 | tr '[:lower:]' '[:upper:]')
  [ -z "$CHANTIER" ] && CHANTIER="UNKNOWN"
  case "$REL" in
    *.py) TYPE="code/python" ;;
    *.js|*.jsx|*.ts|*.tsx) TYPE="code/js" ;;
    *.yaml|*.yml) TYPE="config/yaml" ;;
    *.json) TYPE="config/json" ;;
    *.md) TYPE="docs" ;;
    *.sql) TYPE="db/sql" ;;
    *.sh) TYPE="script/shell" ;;
    *.zip) TYPE="archive/zip" ;;
    *) TYPE="file" ;;
  esac
  echo "$REL,$CHANTIER,$TYPE,STAGING," >> "manifests/inventory.csv"
done
)
ls -l "manifests/inventory.csv"

Tu as raison. Voici un seul bloc de commandes, sans commentaires ni parenthèses, pour installer le serveur local et l’extension Chrome, puis lancer le serveur :
bashCopier le codechmod +x "/Users/nathalie/Dropbox/PROJETS/EURKAI/INBOX_EURKAI/auto_inventory.sh"
mkdir -p "$HOME/EURKAI_CHROME_BUTTON/LOCAL_RUNNER"
cat > "$HOME/EURKAI_CHROME_BUTTON/LOCAL_RUNNER/server.py" << 'PY'
from flask import Flask, jsonify
from flask_cors import CORS
import subprocess, os
APP = Flask(__name__)
CORS(APP, resources={r"/*": {"origins": ["http://localhost:*","chrome-extension://*"]}})
SCRIPT = "/Users/nathalie/Dropbox/PROJETS/EURKAI/INBOX_EURKAI/auto_inventory.sh"
@APP.post("/run_inventory")
def run_inventory():
    if not os.path.exists(SCRIPT):
        return jsonify({"status":"error","output":f"Script introuvable: {SCRIPT}"}), 404
    try:
        proc = subprocess.run(["bash", SCRIPT], cwd=os.path.dirname(SCRIPT), capture_output=True, text=True, timeout=120)
        status = "ok" if proc.returncode == 0 else f"fail({proc.returncode})"
        return jsonify({"status":status, "output": (proc.stdout + '\n' + proc.stderr).strip()})
    except Exception as e:
        return jsonify({"status":"error","output":str(e)}), 500
if __name__ == "__main__":
    APP.run(host="127.0.0.1", port=5050, debug=False)
PY
cat > "$HOME/EURKAI_CHROME_BUTTON/install_and_run.sh" << 'SH'
#!/usr/bin/env bash
set -e
cd "$(dirname "$0")/LOCAL_RUNNER"
python3 -m venv .venv
source .venv/bin/activate
pip install flask flask-cors
python server.py
SH
chmod +x "$HOME/EURKAI_CHROME_BUTTON/install_and_run.sh"
mkdir -p "$HOME/EURKAI_CHROME_BUTTON/extension"
cat > "$HOME/EURKAI_CHROME_BUTTON/extension/manifest.json" << 'JSON'
{
  "manifest_version": 3,
  "name": "EURKAI Inventory",
  "version": "1.0.0",
  "description": "Mettre à jour l’inventaire EURKAI depuis la barre Chrome.",
  "action": { "default_title": "Mettre à jour l’inventaire" },
  "background": { "service_worker": "service_worker.js" },
  "permissions": ["notifications"],
  "host_permissions": ["http://127.0.0.1:5050/*"],
  "icons": { "16": "icon-16.png", "48": "icon-48.png", "128": "icon-128.png" }
}
JSON
cat > "$HOME/EURKAI_CHROME_BUTTON/extension/service_worker.js" << 'JS'
chrome.action.onClicked.addListener(async () => {
  try {
    const res = await fetch("http://127.0.0.1:5050/run_inventory", { method: "POST" });
    const data = await res.json();
    const ok = data && data.status && data.status.startsWith("ok");
    chrome.notifications.create({
      type: "basic",
      iconUrl: "icon-128.png",
      title: "EURKAI",
      message: ok ? "Inventaire mis à jour ✅" : ("Échec ❌\n" + (data.output || ""))
    });
  } catch (e) {
    chrome.notifications.create({
      type: "basic",
      iconUrl: "icon-128.png",
      title: "EURKAI",
      message: "Serveur local indisponible ❌\nLance install_and_run.sh"
    });
  }
});
